#: Mapping of the ``process_priority`` values accepted by :class:`Editor`
#: to the ``nice`` value used to adjust priority on Unix-like systems.
_UNIX_PRIORITY_NICE_VALUES = {
    "low": 10,
    "below_normal": 5,
    "normal": 0,
    "above_normal": -5,
    "high": -10,
}


class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension

        if process_priority not in _UNIX_PRIORITY_NICE_VALUES:
            process_priority = None

        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _get_windows_priority_class(self) -> int | None:
        import subprocess

        return {
            "low": subprocess.IDLE_PRIORITY_CLASS,
            "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,
            "normal": subprocess.NORMAL_PRIORITY_CLASS,
            "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,
            "high": subprocess.HIGH_PRIORITY_CLASS,
        }.get(self.process_priority)

    def _set_unix_priority(self, pid: int) -> None:
        nice_value = _UNIX_PRIORITY_NICE_VALUES.get(self.process_priority)  # type: ignore[arg-type]

        if nice_value is None:
            return

        try:
            os.setpriority(os.PRIO_PROCESS, pid, nice_value)
        except (AttributeError, OSError, PermissionError):
            # os.setpriority is unavailable, or the process doesn't have
            # permission to change priority (e.g. increasing it without
            # sufficient privileges). Fall back to default priority.
            pass

    def edit_file(self, filename: str) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        kwargs: dict[str, t.Any] = {}

        if self.process_priority is not None and WIN:
            priority_class = self._get_windows_priority_class()

            if priority_class is not None:
                kwargs["creationflags"] = priority_class

        try:
            c = subprocess.Popen(
                f'{editor} "{filename}"', env=environ, shell=True, **kwargs
            )

            if self.process_priority is not None and not WIN:
                self._set_unix_priority(c.pid)

            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

